import statistics as stats
def analyze_temperature_data(temperatures):
    """
    Analyze temperature data and return statistics.

    Args:
        temperatures (list): List of daily temperatures in Fahrenheit

    Returns:
        dict: Dictionary with keys 'mean', 'median', 'extreme_days', 'classification'
    """
    # Your code here
    Mean = stats.mean(temperatures)
    Median = stats.median(temperatures)
    Very_hot = sum(i for temp in temperatures if temp > 90)
    freezing = sum(i for temp in temperatures if temp < 32)
    hot = sum(i for temp in temperatures if temp > 80)

    extreme_days = Very_hot + freezing
    classification = ''

    for temp in temperatures:
        if Mean  > 80:
          classification ='Hot'  
        elif Mean < 50:
            classification = 'Cold'
        else:
            classification = "Moderate"

    return {Mean, Median, extreme_days, classification}

    pass
temps1 = [72, 68, 75, 70, 73, 69, 71]
analyze_temperature_data(temps1)
