def calculate_shopping_cart_total(cart, is_member):
    """
    Calculate the final total for a shopping cart.

    Args:
        cart (list): List of item dicts with 'item', 'price', 'quantity', 'category'
        is_member (bool): Whether customer has membership

    Returns:
        float: Final total rounded to 2 decimal places
    """
    # Your code here
    cart_total = 0

    for items in cart:
        # **Quantity discounts:** If buying 3 or more of the same item, that item gets 10% off
        total = calculate_item_total({'price': items.get("price"), 'quantity': items.get("quantity")})
    
        cart_total = cart_total + total

        #print(f'total: {total}')

    #print(f'total: {cart_total}')

    #**Membership discount:** Members get 15% off the entire order
    discount = cart_total * 0.85 if is_member else cart_total  
    #print(f'Discount: {discount}')

    #**Tax:** Apply 8% sales tax on the discounted total (before shipping)
    tax = discount * 1.08

    #**Shipping:** Orders over $100 get free shipping, otherwise add $10 for shipping
    cart_total = tax if cart_total > 100 else tax + 10
    #print(f'total: {cart_total}')

#**Return the final total** (after all discounts, tax, and shipping)
    return round(cart_total, 2)

