def clean_product_data(product_names, product_prices):
    """
    Clean product names and prices.
    
    Args:
        product_names (list): List of messy product names
        product_prices (list): List of price strings
        
    Returns:
        tuple: (cleaned_names, cleaned_prices)
    """
    # Your code here
    cleaned_names = []
    cleaned_prices = []

    listName = product_names

    #strips white space and change to lowercase
    for name in listName:
        new_name = name.strip().lower() 
        cleaned_names.append(new_name) #append to clean names
        
    for price in product_prices:
        new_price =float(price.replace('$', ''))
        cleaned_prices.append(new_price)
  
    print(cleaned_names)
    print(cleaned_prices)
    return [cleaned_names, cleaned_prices]


