def analyze_revenue(transactions):
    """
    Analyze sales data to find total, mean, median, mode, stdev, percentile, and high-value counts.

    Args:
        transactions (list): List of floats representing transaction amounts

    Returns:
        dict: Dictionary with all required keys
    """
    # Your code here
    quartile = statistics.quantiles(transactions, n=4)
    revenue = {
        # Calculates total sum of transactions
        
        'total_revenue': sum(transactions),
        
        # Uses statistics.mean for the average
        'mean': round(statistics.mean(transactions), 2),
        
        # Uses statistics.median for the middle value
        'median': round(statistics.median(transactions), 2),
        
        # Uses statistics.mode for the value appears most
        'mode': statistics.mode(transactions), 
        
        # Uses statistics.stdev for the standard deviation
        'stdev': round(statistics.stdev(transactions), 2),
        
        # Uses the calculated 25th percentile (Q1)
        '25th_percentile': round(quartile[0], 2), 
        
        # Calculates the count of high-value transactions 
        'high_value_count': sum(values > 100 for values in transactions)
    }
    print(revenue['stdev'])
    return revenue
pass
