def analyze_weekly_sales(sales_data):
    """
    Analyze weekly sales data (list of lists).

    Args:
        sales_data (list): List of lists of floats

    Returns:
        tuple: (total_transactions, total_revenue)
    """
    # Your code here (Use nested loops!)
    new_count = 0
    week_data = 0
    for test in sales_data:
        new_count += len(test)
        week_data += sum(test)

    return new_count, week_data
