def segment_customers(transactions):
    """
    Analyze transaction dictionaries.

    Args:
        transactions (list): List of dicts

    Returns:
        tuple: (unique_customer_count, category_totals_dict)
    """
    # Your code here
    #How many *unique* customers shopped with us?
    unique_ids = {ids['id'] for ids in transactions}
    category_totals_dict = len(unique_ids)

    #How much revenue did we make in each category (Electronics vs Clothing)?
    unique_customer_count = {cat['category'] for cat in transactions}
    category_totals_dict = {}

    for name in unique_customer_count:
        total =sum(t['amount'] for t in transactions if t['category'] == name)
        category_totals_dict[name]= float(total)

    return(len(unique_customer_count), category_totals_dict)
    pass
