# GROUP CODE: Create a correlation heatmap
# Hint: Use sns.heatmap() with stroke_df.select_dtypes(include=['number']).corr()
# 1. Calculate the Correlation Matrix
# We use .select_dtypes(include=['number']) to ensure only numeric columns are included
correlation_matrix = stroke_df.select_dtypes(include=['number']).corr()

# 2. Create the Heatmap
plt.figure(figsize=(10, 8)) # Adjust size for better visibility

# sns.heatmap creates the visualization
sns.heatmap(
    correlation_matrix,
    annot=True,     # Display the correlation values on the map
    cmap='coolwarm',# A diverging colormap is best for correlation (shows positive/negative)
    fmt=".2f",      # Format the annotation numbers to two decimal places
    linewidths=.5,  # Add lines between cells for clarity
    cbar_kws={'label': 'Correlation Coefficient'}
)

plt.title('Correlation Heatmap of Numeric Variables')
plt.show()
