def clean_data(df):
    """
    Clean the sales data.
    
    Steps:
    1. Remove duplicate transactions (based on transaction_id)
    2. Fill missing numeric values with median
    3. Fill missing categorical values with mode
    4. Clean product_name (strip whitespace, lowercase)
    5. Remove outliers in customer_age (keep 10-100)
    
    Args:
        df (pd.DataFrame): The raw DataFrame
        
    Returns:
        pd.DataFrame: The cleaned DataFrame
    """
    # IMPORTANT: Make a copy first so we don't modify the original!
    df_clean = df.copy()
    
    # Your code here
    # Step 1: Remove duplicates
    df_clean.drop_duplicates
    
    # Step 2: Fill missing numeric values with median
    # Hint: Use df_clean.select_dtypes(include=[np.number]).columns to get numeric columns
    UP_median_value = df_clean['unit_price'].median()
    TA_median_value = df_clean['total_amount'].median()
    CA_median_value = df_clean['customer_age'].median()

    df_clean['unit_price'].fillna(UP_median_value, inplace = True)
    df_clean['total_amount'].fillna(TA_median_value, inplace = True)
    df_clean['customer_age'].fillna(CA_median_value, inplace = True)
    # Step 3: Fill missing categorical values with mode
    # Hint: Use df_clean.select_dtypes(include=['object']).columns to get categorical columns
    SL_mode_value = df_clean['store_location'].mode()

    df_clean['store_location'].fillna(SL_mode_value, inplace = True)
    # Step 4: Clean product_name
    df_clean['product_name'].str.strip().str.toLower()
    # Step 5: Remove outliers in customer_age
    df_clean = df_clean[(df_clean['customer_age'] >0) & (df_clean['customer_age'] < 100)]

    print(df_clean['customer_age'].describe())
    return df_clean
