def prepare_ml_dataframe(df):
    """
    Prepare the final ML-ready DataFrame.
    
    Steps:
    1. Drop non-useful columns: transaction_id, date, product_name, customer_id
    2. Verify all columns are numeric
    3. Verify no missing values
    
    Args:
        df (pd.DataFrame): The processed DataFrame
        
    Returns:
        pd.DataFrame: The final ML-ready DataFrame
    """
    #stops the pandas warning and keeps the results cleaner
    pd.set_option('future.no_silent_downcasting', True)

    # IMPORTANT: Make a copy first!
    final_df = df.copy()
    
    # Your code here
    # Step 1: Drop non-useful columns
    columns_to_drop = ['transaction_id', 'date', 'product_name', 'customer_id']
    
    final_df = final_df.drop(columns = columns_to_drop)

    #fixes booleen to change true/ false to 1 and 0
    #.infer_objects(copy=False) is needed now when using .replace
    final_df = final_df.replace({True: 1, False: 0}).infer_objects(copy=False)

    #gets the list of column names that have null values
    null_col = final_df.columns[final_df.isnull().any()].tolist()

    #replaces the null values with the median 
    #could use the mean or just dropped then alltogether
    for col in null_col: 
        median_value = final_df[col].median()
        final_df[col] =final_df[col].fillna(median_value)

    return final_df
