# Use X_train_scaled_df, y_train_reg for training
# Use X_test_scaled_df, y_test_reg for testing
degrees = list(range(1, 11))  # 1 through 5
train_mse = []
test_mse = []

for degree in degrees:
    # Create polynomial features
    poly = PolynomialFeatures(degree=degree, include_bias=False)
    X_train_p = poly.fit_transform(X_train_scaled_df)
    X_test_p = poly.transform(X_test_scaled_df)
    
    # Train model
    model = LinearRegression()
    model.fit(X_train_p, y_train_reg)
    
    # Calculate MSE on both train and test
    y_train_pred = model.predict(X_train_p)
    y_test_pred = model.predict(X_test_p)
    
    train_error = mean_squared_error(y_train_reg, y_train_pred)
    test_error = mean_squared_error(y_test_reg, y_test_pred)
    
    train_mse.append(train_error)
    test_mse.append(test_error)

# Print summary for key degrees
print("Key results:")
for d in [1, 2, 3, 5, 10]:
    idx = d - 1  # Convert degree to index
    print(f"Degree {d:2d}: Train MSE = {train_mse[idx]:,.0f}, Test MSE = {test_mse[idx]:,.0f}")
