# 2. Create the importance table
importance = pd.DataFrame({
    'Feature': X_train_scaled_df.columns,
    'Weight': lasso.coef_
})

# 3. Look for "Weak" columns (weights very close to zero)
# We use .abs() because a negative weight is still "useful"
weak_threshold = 0.01 
weak_columns = importance[importance['Weight'].abs() < weak_threshold]

print("Columns that contribute almost nothing:")
print(weak_columns)
