print("=" * 50)
print("FORWARD PROPAGATION")
print("=" * 50)

# Step 1: Input to Hidden Layer
print("\n--- STEP 1: Input → Hidden Layer ---")
z1 = np.dot(W1, X) + b1
print(f"Weighted sum (z1): {z1}")

a1 = relu(z1)
print(f"After ReLU (a1):   {a1}")

# Step 2: Hidden to Output Layer
