    df_prep['is_member'] = df_prep['is_member'].map({'Yes': 1, 'No': 2})

    #Encode customer_tier ordinally (Bronze=0, Silver=1, Gold=2, Platinum=3)
    df_prep['customer_tier'] = df_prep['customer_tier'].map({'Bronze': 0, 'Silver': 1, 'Gold': 2, 'Platinum':3})

    #One-hot encode region
    df_prep = pd.get_dummies(df_prep, columns=['region'], drop_first=True, dtype=int)

