def prepare_features(df):
    """
    Prepare features for machine learning.
    
    Steps:
    1. Drop customer_id
    2. Fill missing values with median
    3. Encode is_member (Yes=1, No=0)
    4. Encode customer_tier ordinally (Bronze=0, Silver=1, Gold=2, Platinum=3)
    5. One-hot encode region
    6. Scale numeric features using StandardScaler
    
    Args:
        df (pd.DataFrame): The raw DataFrame
        
    Returns:
        pd.DataFrame: The prepared DataFrame with all numeric columns (scaled)
    """
    # IMPORTANT: Make a copy first so we don't modify the original!
    df_prep = df.copy()
    #Drop customer_id
    df_prep = df_prep.drop(columns='customer_id')

    #get median value for columns with missing values
    age_median = df_prep['age'].median()
    website_median = df_prep['website_visits_monthly'].median()
    email_median = df_prep['email_click_rate'].median()

    #Fill missing values with median
    df_prep['age']= df_prep['age'].fillna(age_median)
    df_prep['website_visits_monthly'] = df_prep['website_visits_monthly'].fillna(website_median)
    df_prep['email_click_rate'] = df_prep['email_click_rate'].fillna(email_median)
    
    #Encode is_member (Yes=1, No=0)
    df_prep['is_member'] = df_prep['is_member'].map({'Yes': 1, 'No': 2})

    #Encode customer_tier ordinally (Bronze=0, Silver=1, Gold=2, Platinum=3)
    df_prep['customer_tier'] = df_prep['customer_tier'].map({'Bronze': 0, 'Silver': 1, 'Gold': 2, 'Platinum':3})

    #One-hot encode region
    df_prep = pd.get_dummies(df_prep, columns=['region'], drop_first=True, dtype=int)

    #Scale numeric features using StandardScaler
    scaler = StandardScaler()
    numeric_cols = ['website_visits_monthly', 'age', 'email_click_rate']
    scaled_values = scaler.fit_transform(df_prep[numeric_cols])
    df_prep[numeric_cols] = pd.DataFrame(scaled_values, columns=numeric_cols, index=df_prep.index)
    
    return df_prep
