def prepare_features_for_nn(df):
    """
    Prepare features specifically for neural network training.

    Steps:
    1. Make a copy of the DataFrame
    2. Drop customer_id (not predictive)
    3. Drop annual_spend (not using regression target)
    4. Fill missing age with median
    5. Fill missing website_visits_monthly with median
    6. Fill missing email_click_rate with median
    7. Encode is_member (Yes=1, No=0)
    8. Encode customer_tier ordinally (Bronze=0, Silver=1, Gold=2, Platinum=3)
    9. One-hot encode region (keep all 5 columns)

    Args:
        df (pd.DataFrame): The raw DataFrame

    Returns:
        pd.DataFrame: The prepared DataFrame with all numeric columns
    """
    # IMPORTANT: Make a copy first so we don't modify the original!
    df_prep = df.copy()

    # Drop customer_id (not predictive)
    #Drop annual_spend (not using regression target)
    df_prep = df_prep.drop(columns=['customer_id', 'annual_spend'] )

    #get median value for columns with missing values
    age_median = df_prep['age'].median()
    website_median = df_prep['website_visits_monthly'].median()
    email_median = df_prep['email_click_rate'].median()

    #Fill missing values with median
    df_prep['age']= df_prep['age'].fillna(age_median)
    df_prep['website_visits_monthly'] = df_prep['website_visits_monthly'].fillna(website_median)
    df_prep['email_click_rate'] = df_prep['email_click_rate'].fillna(email_median)

    #Encode is_member (Yes=1, No=0)
    df_prep['is_member'] = df_prep['is_member'].map({'Yes': 1, 'No': 2})

    #One-hot encode region
    df_prep = pd.get_dummies(df_prep, columns=['region'], drop_first=False, dtype=int)

    #Encode customer_tier ordinally (Bronze=0, Silver=1, Gold=2, Platinum=3)
    df_prep['customer_tier'] = df_prep['is_member'].map({'Bronze': 0, 'Silver': 2, 'Gold': 2, 'Platinum':3})

    return df_prep
