def create_temporal_features(df: pd.DataFrame) -> pd.DataFrame:
    # 1. Ensure datetime type (prevents AttributeError)
    df['Start_Time'] = pd.to_datetime(df['Start_Time'], errors='coerce')
    if 'End_Time' in df.columns:
        df['End_Time'] = pd.to_datetime(df['End_Time'], errors='coerce')

    # 2. Extract basic components
    df['hour'] = df['Start_Time'].dt.hour
    df['day_of_week'] = df['Start_Time'].dt.dayofweek
    df['month'] = df['Start_Time'].dt.month
    df['is_weekend'] = (df['day_of_week'] >= 5).astype(int)

    # 3. Rush hour flags
    df['is_morning_rush'] = df['hour'].between(7, 9).astype(int)
    df['is_evening_rush'] = df['hour'].between(16, 19).astype(int)
    df['is_rush_hour'] = (df['is_morning_rush'] | df['is_evening_rush']).astype(int)

    # 4. Duration calculation
    if 'End_Time' in df.columns:
        # Result in minutes
        df['duration_min'] = (df['End_Time'] - df['Start_Time']).dt.total_seconds() / 60
        df['duration_min'] = df['duration_min'].clip(0, 1440) 

    # 5. Simple "Is Dark" (Optional logic: Night is typically 8pm - 6am)
    df['is_night'] = ((df['hour'] >= 20) | (df['hour'] <= 6)).astype(int)

    return df
