df_City_Traffic = create_temporal_features(df_City_Traffic)

# 2. Now run the map code
import folium
from folium.plugins import HeatMapWithTime

hourly_data = []
for hour in range(24):
    # This will now work because 'hour' exists in df_City_Traffic
    subset = df_City_Traffic[df_City_Traffic['hour'] == hour]
    
    # Clean out NaNs so Folium doesn't crash
    points = subset[['Start_Lat', 'Start_Lng']].dropna().values.tolist()
    hourly_data.append(points)

# Create and save the map
m = folium.Map(location=[37.0902, -95.7129], zoom_start=4)
HeatMapWithTime(
    hourly_data, 
    index=[f"{h}:00" for h in range(24)],
    radius=10, 
    auto_play=True, 
    max_opacity=0.8
).add_to(m)

m.save("interactive_traffic_map.html")
print("Map generated successfully!")
