from uszipcode import SearchEngine

search = SearchEngine()

def get_zip_from_coords(lat, lng):
    # Find the closest zipcode within 5 miles of the coordinates
    result = search.by_coordinates(lat, lng, radius=5, returns=1)
    if result:
        return result[0].zipcode
    return None

# Find rows where Zipcode is missing
missing_zip_mask = df_City_Traffic['Zipcode'].isna()

# Only run this on the missing rows to save time
df_City_Traffic.loc[missing_zip_mask, 'Zipcode'] = df_City_Traffic[missing_zip_mask].apply(
    lambda row: get_zip_from_coords(row['Start_Lat'], row['Start_Lng']), axis=1
)

print(f"Zipcodes recovered: {missing_zip_mask.sum()}")
