df_City_Traffic.loc[missing_zip_mask, 'Zipcode'] = df_City_Traffic[missing_zip_mask].apply(
    lambda row: get_zip_from_coords(row['Start_Lat'], row['Start_Lng']), axis=1
)

print(f"Zipcodes recovered: {missing_zip_mask.sum()}")
