from uszipcode import SearchEngine

# Initialize the engine
search = SearchEngine()

# 1. Identify rows where Zipcode is 'missing' or NaN
# (Note: In your In [342], you filled nulls with 'missing')
mask = (df_City_Traffic['Zipcode'] == 'missing') | (df_City_Traffic['Zipcode'].isna())
null_coords = df_City_Traffic[mask][['Start_Lat', 'Start_Lng']].drop_duplicates()

print(f"Unique coordinate pairs to look up: {len(null_coords)}")

# 2. Define the lookup logic
def fetch_zip(lat, lng):
    res = search.by_coordinates(lat, lng, radius=5, returns=1)
    return res[0].zipcode if res else None

# 3. Create a mapping dictionary
zip_map = { (row.Start_Lat, row.Start_Lng): fetch_zip(row.Start_Lat, row.Start_Lng) 
            for row in null_coords.itertuples() }

# 4. Map the results back to the main dataframe
df_City_Traffic.loc[mask, 'Zipcode'] = df_City_Traffic[mask].apply(
    lambda x: zip_map.get((x['Start_Lat'], x['Start_Lng'])), axis=1
)

print("✅ Missing Zipcodes repaired.")
