from geopy.geocoders import Nominatim
from geopy.extra.rate_limiter import RateLimiter

# Initialize the geolocator
geolocator = Nominatim(user_agent="traffic_accident_research")
# Rate limiter helps avoid getting blocked by the API
reverse = RateLimiter(geolocator.reverse, min_delay_seconds=1)

def find_airport_nearby(row):
    try:
        # Search for features near the coordinates
        location = geolocator.reverse(f"{row['Start_Lat']}, {row['Start_Lng']}", exactly_one=True)
        if location and 'address' in location.raw:
            # Check if an airport is mentioned in the address details
            address = location.raw['address']
            # Nominatim often returns 'aeroway' or 'airport' in the details
            return address.get('airport', address.get('aeroway', 'missing'))
    except:
        return 'missing'
    return 'missing'

# 1. Target the rows with missing Airport_Code
ac_mask = (df_City_Traffic['Airport_Code'].isna()) | (df_City_Traffic['Airport_Code'] == 'missing')

# 2. Update them (Only 1,514 rows, so this should take ~20 mins with the rate limiter)
print(f"Finding closest airports for {ac_mask.sum()} rows...")
df_City_Traffic.loc[ac_mask, 'Airport_Code'] = df_City_Traffic[ac_mask].apply(find_airport_nearby, axis=1)
