from scipy.spatial import KDTree
from uszipcode import SearchEngine
import pandas as pd
import numpy as np

def fill_geographic_and_airport_data(df: pd.DataFrame) -> pd.DataFrame:
    search = SearchEngine()
    
    # 1. Create a reference list of all US Zipcodes and their Coordinates
    # We do this once to find the "nearest neighbor" for your missing rows
    all_zips = search.by_coordinates(39.8283, -98.5795, radius=3000, returns=50000)
    zip_ref = pd.DataFrame([{
        'zip': z.zipcode, 
        'lat': z.lat, 
        'lng': z.lng,
        'city': z.major_city,
        'timezone': z.timezone
    } for z in all_zips])

    # 2. Build the Spatial Tree
    tree = KDTree(zip_ref[['lat', 'lng']].values)

    # 3. Identify rows needing repair (City, Zip, Timezone, or Airport)
    mask = (df['Airport_Code'].isna()) | (df['Airport_Code'] == 'missing') | (df['City'] == 'missing')

    if mask.any():
        print(f"Fast-repairing {mask.sum()} geographic rows...")
        coords = df.loc[mask, ['Start_Lat', 'Start_Lng']].values
        distances, indices = tree.query(coords)

        # Pull the nearest data from our reference
        nearest_data = zip_ref.iloc[indices]
        
        # Fill City, Zip, and Timezone
        df.loc[mask, 'Zipcode'] = nearest_data['zip'].values
        df.loc[mask, 'City'] = nearest_data['city'].str.lower().values
        df.loc[mask, 'Timezone'] = 'us/' + nearest_data['timezone'].str.lower().values
        
        # Fill Street with "near [City] center" if it's missing
        if 'Street' in df.columns:
            s_mask = mask & (df['Street'].isna() | (df['Street'] == 'missing'))
            df.loc[s_mask, 'Street'] = "near " + df.loc[s_mask, 'City'] + " center"

        # 4. Final step: Map to Airport_Code using your existing lookup_dict
        # lookup_dict was defined in In [331] from your csv
        df.loc[mask, 'Airport_Code'] = 'k' + df.loc[mask, 'Zipcode'].map(lookup_dict).str.lower()
        df['Airport_Code'] = df['Airport_Code'].fillna('missing')

    return df
