from collections import Counter
import re
df = df_City_Traffic.dropna(subset=['Description'])  # Ensure we only analyze rows with descriptions
# Combine all descriptions, lowercase them, and find all words
words = re.findall(r'\w+', ' '.join(df['Description'].dropna()).lower())

# Filter out "stop words" (the, on, at, at, of)
stop_words = {'on', 'at', 'the', 'and', 'of', 'to', 'in', 'from', 'near'}
keywords = Counter([w for w in words if w not in stop_words])

print(keywords.most_common(20))
