# Visualize Severity by different features
fig, axes = plt.subplots(2,2,figsize = (12,10))

colors = {0: "#E1897F", 1: "#79813E"}

# Plot 1: Average Severity Based on Severity
exp_order = ['EN', 'MI', 'SE', 'EX']
Severity_experience = df_City_Traffic.groupby('Visibility(mi)')[TARGET].mean().reindex(exp_order)
axes[0,0].bar(Severity_experience.index, Severity_experience.values, color=['#3498DB', '#9B59B6', '#E67E22'])
axes[0,0].set_xlabel('Visibility')
axes[0,0].set_ylabel('Severity')
axes[0,0].set_title('Average Severity Based on Visibility')
axes[0,0].set_xticklabels(['Level', 'Level', 'Level', 'Level' ])

# Plot 2: Average Severity Based on Precipitation
# Group by the exact precipitation value and calculate the mean severity
severity_avg_by_precip = df_City_Traffic.groupby('Precipitation(in)')[TARGET].mean()

# Plot the averages as a simple scatter plot
# x = the unique precipitation values (index)
# y = the average severity for each value
axes[0,1].scatter(
    severity_avg_by_precip.index, 
    severity_avg_by_precip.values, 
    color='#3498DB', 
    s=15, 
    alpha=0.8
)

axes[0,1].set_xlabel('Precipitation (in)')
axes[0,1].set_ylabel('Average Severity')
axes[0,1].set_title('Average Severity vs. Precipitation')

# Remove the categorical labels since we are now using the continuous scale
axes[0,1].set_xticks(axes[0,1].get_xticks())

